import sys

class Solution:
    def findMedianSortedArrays(self, nums1: list[int], nums2: list[int]) -> float:
        # Ensure nums1 is the smaller array
        if len(nums1) > len(nums2):
            nums1, nums2 = nums2, nums1
        m, n = len(nums1), len(nums2)
        total = m + n
        half = (total + 1) // 2
        left, right = 0, m
        while left <= right:
            i = (left + right) // 2  # partition nums1
            j = half - i            # partition nums2
            nums1_left = nums1[i - 1] if i > 0 else -float('inf')
            nums1_right = nums1[i] if i < m else float('inf')
            nums2_left = nums2[j - 1] if j > 0 else -float('inf')
            nums2_right = nums2[j] if j < n else float('inf')
            if nums1_left <= nums2_right and nums2_left <= nums1_right:
                if total % 2:
                    return float(max(nums1_left, nums2_left))
                else:
                    return (max(nums1_left, nums2_left) + min(nums1_right, nums2_right)) / 2.0
            elif nums1_left > nums2_right:
                right = i - 1
            else:
                left = i + 1
        # Should never reach here if input arrays are valid
        raise ValueError("Input arrays are not sorted or empty")

if __name__ == '__main__':
    it = iter(sys.stdin.read().split())
    try:
        m = int(next(it))
        nums1 = [int(next(it)) for _ in range(m)]
        n = int(next(it))
        nums2 = [int(next(it)) for _ in range(n)]
    except StopIteration:
        sys.exit(0)
    sol = Solution()
    median = sol.findMedianSortedArrays(nums1, nums2)
    # Print without unnecessary trailing zeros but keep at least one decimal place
    if median == int(median):
        print(f"{median:.1f}")
    else:
        print(median)

