#include <bits/stdc++.h>
using namespace std;

class Solution {
public:
    double findMedianSortedArrays(vector<int>& nums1, vector<int>& nums2) {
        // Ensure nums1 is the smaller array
        if (nums1.size() > nums2.size())
            return findMedianSortedArrays(nums2, nums1);
        int m = nums1.size();
        int n = nums2.size();
        int total = m + n;
        int half = (total + 1) / 2;
        int left = 0, right = m;
        while (left <= right) {
            int i = (left + right) / 2; // partition nums1
            int j = half - i;           // partition nums2
            double nums1_left = (i == 0) ? -numeric_limits<double>::infinity() : nums1[i - 1];
            double nums1_right = (i == m) ? numeric_limits<double>::infinity() : nums1[i];
            double nums2_left = (j == 0) ? -numeric_limits<double>::infinity() : nums2[j - 1];
            double nums2_right = (j == n) ? numeric_limits<double>::infinity() : nums2[j];
            if (nums1_left <= nums2_right && nums2_left <= nums1_right) {
                if (total % 2 == 1) {
                    return max(nums1_left, nums2_left);
                } else {
                    return (max(nums1_left, nums2_left) + min(nums1_right, nums2_right)) / 2.0;
                }
            } else if (nums1_left > nums2_right) {
                right = i - 1;
            } else {
                left = i + 1;
            }
        }
        // Should not reach here for valid input
        return 0.0;
    }
};

int main() {
    ios::sync_with_stdio(false);
    cin.tie(nullptr);
    int m;
    if (!(cin >> m)) return 0;
    vector<int> nums1(m);
    for (int i = 0; i < m; ++i) cin >> nums1[i];
    int n;
    if (!(cin >> n)) return 0;
    vector<int> nums2(n);
    for (int i = 0; i < n; ++i) cin >> nums2[i];
    Solution sol;
    double median = sol.findMedianSortedArrays(nums1, nums2);
    // Output with at least one decimal place
    if (floor(median) == median) {
        cout.setf(ios::fixed);
        cout << setprecision(1) << median << "\n";
    } else {
        cout << median << "\n";
    }
    return 0;
}
